import org.yaml.snakeyaml.parser.ParserException;
import org.yaml.snakeyaml.scanner.ScannerException;

/**
 * Service class for parsing YAML content using SnakeYAML library.
 */
public class YamlService {

    // Reusable Yaml parser instance (thread-safe after initialization)
    private static final Yaml yamlParser = new Yaml();

    /**
     * Parses user-provided YAML content into Java objects.
     * Supports complex structures including nested objects and arrays.
     *
     * @param yamlContent YAML string to parse
     * @return Parsed Java object (Map, List, or primitive wrapper)
     * @throws RuntimeException if parsing fails due to invalid YAML structure
     */
    public Object parseUserYaml(String yamlContent) {
        if (yamlContent == null || yamlContent.trim().isEmpty()) {
            // Handle empty input gracefully
            return null;
        }

        try {
            return yamlParser.load(yamlContent);
        } catch (ScannerException e) {
            // Handle lexical errors like invalid indentation
            throw new RuntimeException("Invalid YAML structure: " + e.getMessage(), e);
        } catch (ParserException e) {
            // Handle syntax errors like unexpected tokens
            throw new RuntimeException("YAML syntax error: " + e.getMessage(), e);
        } catch (YAMLException e) {
            // Handle general YAML parsing errors
            throw new RuntimeException("YAML parsing failed: " + e.getMessage(), e);
        } catch (Exception e) {
            // Catch-all for unexpected exceptions
            throw new RuntimeException("Unexpected error during YAML parsing", e);
        }
    }
}

